class Solution:
    def continuousSubarrays(self, nums: List[int]) -> int:
        from collections import deque

        count = 0
        qmin = deque()
        qmax = deque()

        left = 0
        for right in range(len(nums)):
            # Maintain max queue
            while qmax and nums[right] > nums[qmax[-1]]:
                qmax.pop()
            qmax.append(right)

            # Maintain min queue
            while qmin and nums[right] < nums[qmin[-1]]:
                qmin.pop()
            qmin.append(right)

            # Ensure the difference between max and min is <= 2
            while nums[qmax[0]] - nums[qmin[0]] > 2:
                left += 1
                if qmax[0] < left:
                    qmax.popleft()
                if qmin[0] < left:
                    qmin.popleft()

            # All subarrays ending at right and starting from left to right are valid
            count += right - left + 1

        return count
